"use client"

import { useMemo, useState, useEffect } from "react"
import { useAuthStore } from "@/store/auth-store"
import { useDataStore, type Report, type Team, type Engineer } from "@/store/data-store"
import { PageHeader } from "@/components/shared/page-header"
import { ReportStatusBadge, PriorityBadge } from "@/components/shared/status-badge"
import { ConfirmDialog } from "@/components/shared/confirm-dialog"
import { Card, CardContent } from "@/components/ui/card"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogHeader,
  DialogTitle,
  DialogFooter,
} from "@/components/ui/dialog"
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select"
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu"
import {
  Search,
  Filter,
  MoreHorizontal,
  ClipboardCheck,
  UserCog,
  Users,
  MapPin,
  AlertTriangle,
} from "lucide-react"
import { toast } from "sonner"

type ReportStatus = "new" | "assigned" | "in_progress" | "pending_approval" | "approved" | "rejected" | "closed"
type ReportPriority = "low" | "medium" | "high" | "critical"

const STATUS_FILTERS: { value: "all" | ReportStatus; label: string }[] = [
  { value: "all", label: "All Status" },
  { value: "new", label: "New" },
  { value: "assigned", label: "Assigned" },
  { value: "in_progress", label: "In Progress" },
  { value: "pending_approval", label: "Pending Approval" },
  { value: "approved", label: "Approved" },
  { value: "rejected", label: "Rejected" },
  { value: "closed", label: "Closed" },
]

const PRIORITY_FILTERS: { value: "all" | ReportPriority; label: string }[] = [
  { value: "all", label: "All Priority" },
  { value: "low", label: "Low" },
  { value: "medium", label: "Medium" },
  { value: "high", label: "High" },
  { value: "critical", label: "Critical" },
]

export default function ReportsPage() {
  const { currentUser } = useAuthStore()
  const { reports, teams, engineers, fetchReports, fetchTeams, fetchEngineers, updateReport } = useDataStore()

  const [search, setSearch] = useState("")
  const [statusFilter, setStatusFilter] = useState<"all" | ReportStatus>("all")
  const [priorityFilter, setPriorityFilter] = useState<"all" | ReportPriority>("all")
  const [detailOpen, setDetailOpen] = useState(false)
  const [assignOpen, setAssignOpen] = useState(false)
  const [approveDialogOpen, setApproveDialogOpen] = useState(false)
  const [rejectDialogOpen, setRejectDialogOpen] = useState(false)
  const [selectedReport, setSelectedReport] = useState<Report | null>(null)

  // Fetch data on mount
  useEffect(() => {
    fetchReports()
    fetchTeams()
    fetchEngineers()
  }, [fetchReports, fetchTeams, fetchEngineers])

  const isAdmin = currentUser?.role === "admin"
  const isUtility = currentUser?.role === "utility_manager"
  const isDMA = currentUser?.role === "dma_manager"

  // Scope reports based on role
  const scopedReports = useMemo(() => {
    if (!currentUser) return []
    if (isAdmin) return reports
    if (isUtility) {
      return reports.filter((r) => r.utilityId === currentUser.id)
    }
    if (isDMA) {
      return reports.filter((r) => r.dmaId === currentUser.id)
    }
    return []
  }, [currentUser, isAdmin, isUtility, isDMA, reports])

  const filteredReports = useMemo(
    () =>
      scopedReports.filter((r) => {
        const query = search.toLowerCase()
        const matchesSearch =
          !query ||
          r.trackingId.toLowerCase().includes(query) ||
          r.description.toLowerCase().includes(query) ||
          (r.address?.toLowerCase() || "").includes(query) ||
          r.dmaName.toLowerCase().includes(query)

        const matchesStatus =
          statusFilter === "all" ? true : r.status === statusFilter

        const matchesPriority =
          priorityFilter === "all" ? true : r.priority === priorityFilter

        return matchesSearch && matchesStatus && matchesPriority
      }),
    [scopedReports, search, statusFilter, priorityFilter]
  )

  const canAssign = isDMA
  const canApproveReject = isDMA

  // Get teams and engineers for DMA manager
  const dmaId = currentUser?.id ?? ""
  const districtTeams = teams.filter((t) => t.dmaId === dmaId)
  const districtEngineers = engineers.filter((e) => e.dmaId === dmaId)

  // Assignment form state
  const [assignTeamId, setAssignTeamId] = useState("")
  const [assignEngineerId, setAssignEngineerId] = useState("")

  function openDetail(report: Report) {
    setSelectedReport(report)
    setDetailOpen(true)
  }

  function openAssign(report: Report) {
    setSelectedReport(report)
    setAssignTeamId(report.teamId ?? "")
    setAssignEngineerId(report.assignedEngineerId ?? "")
    setAssignOpen(true)
  }

  function openApprove(report: Report) {
    setSelectedReport(report)
    setApproveDialogOpen(true)
  }

  function openReject(report: Report) {
    setSelectedReport(report)
    setRejectDialogOpen(true)
  }

  async function handleAssign() {
    if (!selectedReport) return
    if (!assignTeamId || !assignEngineerId) {
      toast.error("Please select both team and engineer.")
      return
    }

    const team = teams.find((t) => t.id === assignTeamId)
    const engineer = engineers.find((e) => e.id === assignEngineerId)

    try {
      await updateReport(selectedReport.id, {
        teamId: assignTeamId,
        teamName: team?.name,
        assignedEngineerId: assignEngineerId,
        assignedEngineerName: engineer?.name,
        status: "assigned",
      })
      toast.success("Report assigned successfully")
      setAssignOpen(false)
    } catch {
      toast.error("Failed to assign report")
    }
  }

  async function handleApprove() {
    if (!selectedReport) return
    try {
      await updateReport(selectedReport.id, { status: "approved" })
      toast.success("Report approved and marked as resolved")
      setApproveDialogOpen(false)
    } catch {
      toast.error("Failed to approve report")
    }
  }

  async function handleReject() {
    if (!selectedReport) return
    try {
      await updateReport(selectedReport.id, { status: "rejected" })
      toast.success("Report rejected")
      setRejectDialogOpen(false)
    } catch {
      toast.error("Failed to reject report")
    }
  }

  return (
    <div className="flex flex-col gap-6">
      <PageHeader
        title="Reports"
        description={
          isDMA
            ? "Assign and manage leakage reports in your DMA"
            : isUtility
              ? "Monitor reports across your utility"
              : "National view of all leakage reports"
        }
      />

      {/* Filters */}
      <div className="flex flex-col gap-3 sm:flex-row sm:items-center">
        <div className="relative flex-1 max-w-md">
          <Search className="absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-muted-foreground" />
          <Input
            placeholder="Search by tracking ID, address, or DMA..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="pl-9"
          />
        </div>
        <div className="flex flex-wrap items-center gap-2">
          <Filter className="hidden h-4 w-4 text-muted-foreground sm:block" />
          <Select
            value={statusFilter}
            onValueChange={(v) => setStatusFilter(v as typeof statusFilter)}
          >
            <SelectTrigger className="w-40">
              <SelectValue placeholder="Status" />
            </SelectTrigger>
            <SelectContent>
              {STATUS_FILTERS.map((s) => (
                <SelectItem key={s.value} value={s.value}>
                  {s.label}
                </SelectItem>
              ))}
            </SelectContent>
          </Select>
          <Select
            value={priorityFilter}
            onValueChange={(v) => setPriorityFilter(v as typeof priorityFilter)}
          >
            <SelectTrigger className="w-32">
              <SelectValue placeholder="Priority" />
            </SelectTrigger>
            <SelectContent>
              {PRIORITY_FILTERS.map((p) => (
                <SelectItem key={p.value} value={p.value}>
                  {p.label}
                </SelectItem>
              ))}
            </SelectContent>
          </Select>
        </div>
      </div>

      {/* Table */}
      <Card>
        <CardContent className="p-0">
          <div className="overflow-x-auto">
            <table className="w-full text-sm">
              <thead>
                <tr className="border-b text-left text-muted-foreground">
                  <th className="px-6 py-3 font-medium">Tracking ID</th>
                  <th className="px-6 py-3 font-medium">Summary</th>
                  <th className="px-6 py-3 font-medium">Location</th>
                  {!isDMA && (
                    <th className="px-6 py-3 font-medium">DMA</th>
                  )}
                  <th className="px-6 py-3 font-medium">Priority</th>
                  <th className="px-6 py-3 font-medium">Status</th>
                  {isDMA && (
                    <th className="px-6 py-3 font-medium">Assigned To</th>
                  )}
                  <th className="px-6 py-3 font-medium text-right">Actions</th>
                </tr>
              </thead>
              <tbody className="divide-y">
                {filteredReports.length === 0 ? (
                  <tr>
                    <td
                      colSpan={isDMA ? 8 : 7}
                      className="px-6 py-12 text-center text-muted-foreground"
                    >
                      No reports found for the selected filters
                    </td>
                  </tr>
                ) : (
                  filteredReports.map((report) => (
                    <tr key={report.id} className="hover:bg-muted/50">
                      <td className="px-6 py-4 font-mono text-xs font-semibold">
                        {report.trackingId}
                      </td>
                      <td className="max-w-xs px-6 py-4 text-muted-foreground">
                        <p className="truncate">{report.description}</p>
                      </td>
                      <td className="px-6 py-4 text-muted-foreground">
                        <div className="flex items-center gap-1.5">
                          <MapPin className="h-3.5 w-3.5" />
                          <span className="truncate max-w-[220px]">
                            {report.address}
                          </span>
                        </div>
                      </td>
                      {!isDMA && (
                        <td className="px-6 py-4 text-muted-foreground">
                          {report.dmaName}
                        </td>
                      )}
                      <td className="px-6 py-4">
                        <PriorityBadge priority={report.priority} />
                      </td>
                      <td className="px-6 py-4">
                        <ReportStatusBadge status={report.status} />
                      </td>
                      {isDMA && (
                        <td className="px-6 py-4 text-muted-foreground">
                          {report.teamName ? (
                            <div className="flex flex-col text-xs">
                              <span className="font-medium flex items-center gap-1">
                                <UserCog className="h-3 w-3 text-muted-foreground" />
                                {report.teamName}
                              </span>
                              {report.assignedEngineerName && (
                                <span className="mt-0.5 flex items-center gap-1">
                                  <Users className="h-3 w-3 text-muted-foreground" />
                                  {report.assignedEngineerName}
                                </span>
                              )}
                            </div>
                          ) : (
                            <span className="text-xs text-amber-600 flex items-center gap-1">
                              <AlertTriangle className="h-3 w-3" />
                              Unassigned
                            </span>
                          )}
                        </td>
                      )}
                      <td className="px-6 py-4 text-right">
                        <DropdownMenu>
                          <DropdownMenuTrigger asChild>
                            <Button
                              variant="ghost"
                              size="icon"
                              className="h-8 w-8"
                            >
                              <MoreHorizontal className="h-4 w-4" />
                              <span className="sr-only">Actions</span>
                            </Button>
                          </DropdownMenuTrigger>
                          <DropdownMenuContent align="end">
                            <DropdownMenuItem onClick={() => openDetail(report)}>
                              View Details
                            </DropdownMenuItem>
                            {canAssign && (
                              <DropdownMenuItem onClick={() => openAssign(report)}>
                                Assign to Team
                              </DropdownMenuItem>
                            )}
                            {canApproveReject &&
                              report.status === "pending_approval" && (
                                <>
                                  <DropdownMenuItem
                                    onClick={() => openApprove(report)}
                                  >
                                    Approve Repair
                                  </DropdownMenuItem>
                                  <DropdownMenuItem
                                    onClick={() => openReject(report)}
                                    className="text-red-600 focus:text-red-600"
                                  >
                                    Reject Repair
                                  </DropdownMenuItem>
                                </>
                              )}
                          </DropdownMenuContent>
                        </DropdownMenu>
                      </td>
                    </tr>
                  ))
                )}
              </tbody>
            </table>
          </div>
        </CardContent>
      </Card>

      {/* Detail dialog */}
      <Dialog open={detailOpen} onOpenChange={setDetailOpen}>
        <DialogContent className="max-w-xl">
          <DialogHeader>
            <DialogTitle>Report Details</DialogTitle>
            <DialogDescription>
              View complete information about this leakage report.
            </DialogDescription>
          </DialogHeader>
          {selectedReport && (
            <div className="flex flex-col gap-4 py-4 text-sm">
              <div className="grid grid-cols-2 gap-4 rounded-lg bg-muted/60 p-4">
                <div>
                  <p className="text-xs text-muted-foreground">Tracking ID</p>
                  <p className="font-mono text-xs font-semibold">
                    {selectedReport.trackingId}
                  </p>
                </div>
                <div>
                  <p className="text-xs text-muted-foreground">Priority</p>
                  <PriorityBadge priority={selectedReport.priority} />
                </div>
                <div>
                  <p className="text-xs text-muted-foreground">Status</p>
                  <ReportStatusBadge status={selectedReport.status} />
                </div>
                <div>
                  <p className="text-xs text-muted-foreground">DMA</p>
                  <p className="font-medium">
                    {selectedReport.dmaName}
                  </p>
                </div>
              </div>

              <div>
                <p className="text-xs text-muted-foreground mb-1.5">
                  Description
                </p>
                <p className="rounded-lg border bg-background px-3 py-2 text-sm leading-relaxed">
                  {selectedReport.description}
                </p>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                  <p className="text-xs text-muted-foreground mb-1.5">
                    Location
                  </p>
                  <p className="flex items-start gap-1.5 text-sm">
                    <MapPin className="mt-0.5 h-3.5 w-3.5 text-muted-foreground" />
                    <span>{selectedReport.address}</span>
                  </p>
                  <p className="mt-1 text-xs text-muted-foreground">
                    Lat {selectedReport.latitude.toFixed(4)} · Lng{" "}
                    {selectedReport.longitude.toFixed(4)}
                  </p>
                </div>
                <div>
                  <p className="text-xs text-muted-foreground mb-1.5">
                    Reporter
                  </p>
                  <p className="font-medium">
                    {selectedReport.reporterName}
                  </p>
                  <p className="text-xs text-muted-foreground">
                    {selectedReport.reporterPhone}
                  </p>
                </div>
              </div>

              {selectedReport.teamName && (
                <div className="grid grid-cols-2 gap-4 rounded-lg bg-muted/40 p-4">
                  <div>
                    <p className="text-xs text-muted-foreground mb-1.5">
                      Assigned Team
                    </p>
                    <p className="flex items-center gap-1.5 text-sm font-medium">
                      <UserCog className="h-4 w-4 text-muted-foreground" />
                      {selectedReport.teamName}
                    </p>
                  </div>
                  {selectedReport.assignedEngineerName && (
                    <div>
                      <p className="text-xs text-muted-foreground mb-1.5">
                        Lead Engineer
                      </p>
                      <p className="flex items-center gap-1.5 text-sm">
                        <Users className="h-4 w-4 text-muted-foreground" />
                        {selectedReport.assignedEngineerName}
                      </p>
                    </div>
                  )}
                </div>
              )}

              <div className="grid grid-cols-3 gap-3 text-xs">
                <div>
                  <p className="text-muted-foreground">Created</p>
                  <p className="font-medium">
                    {new Date(selectedReport.createdAt).toLocaleString("en-ZA")}
                  </p>
                </div>
                <div>
                  <p className="text-muted-foreground">Last Updated</p>
                  <p className="font-medium">
                    {new Date(selectedReport.updatedAt).toLocaleString("en-ZA")}
                  </p>
                </div>
                <div>
                  <p className="text-muted-foreground">SLA Deadline</p>
                  <p className="font-medium">
                    {new Date(selectedReport.slaDeadline).toLocaleString("en-ZA")}
                  </p>
                </div>
              </div>

              {selectedReport.notes && (
                <div>
                  <p className="text-xs text-muted-foreground mb-1.5">
                    Notes
                  </p>
                  <p className="rounded-lg border bg-background px-3 py-2 text-xs leading-relaxed">
                    {selectedReport.notes}
                  </p>
                </div>
              )}
            </div>
          )}
        </DialogContent>
      </Dialog>

      {/* Assign dialog (DMA Manager only) */}
      <Dialog open={assignOpen} onOpenChange={setAssignOpen}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>Assign Report to Team</DialogTitle>
            <DialogDescription>
              Select a team and lead engineer to handle this leakage report.
            </DialogDescription>
          </DialogHeader>
          {selectedReport && (
            <div className="flex flex-col gap-4 py-4">
              <div className="rounded-lg bg-muted/40 p-3 text-xs">
                <p className="font-mono text-[11px] font-semibold">
                  {selectedReport.trackingId}
                </p>
                <p className="mt-1 line-clamp-2 text-muted-foreground">
                  {selectedReport.description}
                </p>
              </div>
              <div className="flex flex-col gap-2">
                <Label>Team</Label>
                <Select
                  value={assignTeamId}
                  onValueChange={(v) => {
                    setAssignTeamId(v)
                    setAssignEngineerId("")
                  }}
                >
                  <SelectTrigger>
                    <SelectValue placeholder="Select team" />
                  </SelectTrigger>
                  <SelectContent>
                    {districtTeams.map((t) => (
                      <SelectItem key={t.id} value={t.id}>
                        {t.name} · {t.branchName}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>
              <div className="flex flex-col gap-2">
                <Label>Lead Engineer</Label>
                <Select
                  value={assignEngineerId}
                  onValueChange={setAssignEngineerId}
                  disabled={!assignTeamId}
                >
                  <SelectTrigger>
                    <SelectValue placeholder="Select engineer" />
                  </SelectTrigger>
                  <SelectContent>
                    {districtEngineers
                      .filter((e) => !assignTeamId || e.teamId === assignTeamId)
                      .map((e) => (
                        <SelectItem key={e.id} value={e.id}>
                          {e.name} · {e.branchName}
                        </SelectItem>
                      ))}
                  </SelectContent>
                </Select>
              </div>
            </div>
          )}
          <DialogFooter>
            <Button variant="outline" onClick={() => setAssignOpen(false)}>
              Cancel
            </Button>
            <Button onClick={handleAssign}>
              <ClipboardCheck className="mr-2 h-4 w-4" />
              Assign Report
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* Approve confirmation */}
      <ConfirmDialog
        open={approveDialogOpen}
        onOpenChange={setApproveDialogOpen}
        title="Approve Repair"
        description="Approve this repair and mark the report as resolved?"
        confirmLabel="Approve Report"
        onConfirm={handleApprove}
      />

      {/* Reject confirmation */}
      <ConfirmDialog
        open={rejectDialogOpen}
        onOpenChange={setRejectDialogOpen}
        title="Reject Repair"
        description="Reject this repair submission and return the report to the team?"
        confirmLabel="Reject Report"
        onConfirm={handleReject}
      />
    </div>
  )
}